import{_ as e,o as t,c as _,ag as a}from"./chunks/framework.DtEl18Xn.js";const r="/getbiji-docs-v3/images/DMFkbWzGCoJ9oRxQkMxcZYAkn9c.png",m=JSON.parse('{"title":"律师用Get笔记搭建知识库，应对重复性咨询问题","description":"","frontmatter":{"title":"律师用Get笔记搭建知识库，应对重复性咨询问题","category":"最佳实践-原来还能这么用","lastUpdated":"2026-03-14T15:01:03.796Z"},"headers":[],"relativePath":"最佳实践-原来还能这么用/律师用get笔记搭建知识库应对重复性咨询问题.md","filePath":"最佳实践-原来还能这么用/律师用get笔记搭建知识库应对重复性咨询问题.md"}'),o={name:"最佳实践-原来还能这么用/律师用get笔记搭建知识库应对重复性咨询问题.md"};function i(l,p,s,n,A,c){return t(),_("div",null,[...p[0]||(p[0]=[a('<h1 id="律师用get笔记搭建知识库-应对重复性咨询问题" tabindex="-1">律师用Get笔记搭建知识库，应对重复性咨询问题 <a class="header-anchor" href="#律师用get笔记搭建知识库-应对重复性咨询问题" aria-label="Permalink to &quot;律师用Get笔记搭建知识库，应对重复性咨询问题&quot;">​</a></h1><p>原文链接：<a href="https://mp.weixin.qq.com/s/1Sz13eGyESV--E097Tn8pw" target="_blank" rel="noreferrer">https://mp.weixin.qq.com/s/1Sz13eGyESV--E097Tn8pw</a></p><p>原创 快刀青衣 快刀青衣 <em>2025年7月15日 07:01 北京</em></p><p>大家好，我叫王喆，是一名专注于海事海商争议解决的执业律师。</p><p>我平时主要处理海上货物运输、海上保险、船舶触碰等这些专业性比较强的案件，但可能你们想不到，找我咨询最多的，却是劳动争议相关的法律问题，比如：</p><ul><li>“用人单位取消已经发放的offer，需要承担什么责任？”</li><li>“用人单位能否以劳动者绩效未达标为由解除劳动合同？”</li></ul><p>很多人觉得，这种日常法律咨询，对我们律师来说是举手之劳，随便“看一眼”就能回答。但现实是，靠谱的律师都有自己深耕的专业领域，我们不可能什么都懂，样样精通。这就像你去医院看病，你要先想清楚自己该挂哪个科室是一样的道理。</p><p>为了回答这些不属于我专业领域的法律咨询，我得查资料、翻法条、找案例，有时候还得请教同行……一上午时间可能就这么搭进去了，我原本的工作计划被彻底打乱，工作效率大打折扣。</p><p>我相信，不止是我，也不止是律师——很多医生、老师、工程师等专业人士都会有同感：你越专业，你的时间就越容易被这种“顺手一问”所绑架。 就在我被这些咨询搞得焦头烂额的时候，AI火起来了。</p><p>一开始，我和很多律师同行一样，对AI既好奇又焦虑。幸运的是，我加入了「得到AI学习圈」。在这里，我一边听刀哥在广播站里分享AI前沿动态，一边跟着老师们学习如何把AI用到自己的工作和生活里。</p><p>慢慢地，我不再被每天的AI新闻裹挟，而是开始反过来思考，AI到底擅长什么？AI在哪些环节能帮到我？哪些AI工具真的好用？而哪些是在割韭菜？</p><p>最关键的启发，还是来自刀哥的一句话： “如果你还不知道怎么让AI怎么落地，就问自己两个问题： 第一，你最想解决的问题是什么？ 第二，你工作中最不想做的三个任务是什么？</p><p>是的，这两个问题，让我一下子豁然开朗：对于我而言，最想解决的，就是那些高频、琐碎、又耗时的日常法律咨询。</p><p>不过我很清楚，AI现在并不完美。 如果直接把法律问题交给通用大模型，不仅风险高，还容易有“幻觉”。</p><p>就算AI没有编造，它给出的法律条文也可能早就被修改甚至废止了——如果未经核实就直接使用，后果不堪设想。</p><p>那么问题来了，怎么能让AI既发挥能力，又尽可能的规避这些风险呢？</p><p>我在AI学习圈的一门课里找到了答案，这门课叫《如何用Get笔记搭建AI知识库》——对，知识库，就是解决像法律这种垂直专业领域知识问答的最佳方案。与其让AI“放飞自我”，不如给它设定一个明确的框架，让它在我给定的范围内发挥能力。</p><p>于是，我就动手搭建了一个劳动争议法律知识库——我还给它起了个谐音梗的名字，叫做《薪知肚明》，“薪”是薪水的“薪”。</p><p>知识库是否靠谱，关键在于你“喂”给AI的内容是不是好东西，所谓好东西，就是权威、准确、最新的信息。</p><p>在我的劳动法知识库中，我把以下三类知识作为核心内容：</p><p>第一类是权威案例：我从人民法院案例库里，把劳动争议相关的指导性案例和参考案例全都挑出来。这些案例都附有法院总结的裁判要旨，不仅权威，而且具有很强的指导意义和参考价值。</p><p>第二类是法律法规与司法解释：包括《劳动法》《劳动合同法》及相关司法解释，关键是，我能保证自己上传的都是现行有效的版本。</p><p>第三类是专业文章：我整理了专业机构、资深律师在公众号上发表的优质文章，以及各地律协发布的劳动争议常见问题的答疑汇总。</p><p>这些内容是我认为一个劳动法争议法律知识库里应该有的好东西。</p><p>也许你会说，如果我“不知道去哪里找好东西”该怎么办？</p><p>没关系，遇事不决问AI！</p><p>比如，我一个海事律师不知道去哪找劳动法领域的优质公众号，我就让AI根据公众号的��营主体、订阅人数、更新频率等指标，帮我筛选出一份名单。</p><p>拿到名单后，我再逐一验证。在这个过程中，我还在名单里发现了一位曾经在得到开课的专业劳动法律师的名字，那么她公众号里面的文章，我就可以基本确定是我需要的好东西。</p><p>至此，我们完成了搭建知识库的最关键一步——去给知识库找好东西。</p><p>接下来，我们需要做的，就是选择一个合适的工具来收集和管理这些好东西。说实话，我也试了不少工具，但最终用下来发现，Get笔记目前是我用起来最趁手的一个，无论是文档、网页、公众号文章、录音，甚至是像今天这种线上直播，Get笔记都可以非常便捷地帮你保存下来。</p><p>当我把上面这三类好东西，一股脑儿上传到Get笔记的知识库里之后，我的劳动争议法律知识库就搭建完成了。</p><p><img src="'+r+'" alt=""></p><p>好东西+好工具=知识库，怎么样，听起来是不是特别简单？如果你愿意，你现在就可以动手搭建自己的知识库了。</p><p>不过，在这里我还想提醒你一点，知识库搭建完成后，千万不能忽略定期更新知识库里的内容。只有不断地把最新的法律法规、权威案例和专业文章都更新进去，你的知识库才能始终保持“战斗力”。</p><p>有了这些精准投喂的知识，我的知识库就不再是一个只会“泛泛而谈”的聊天机器人了，它变成了一个能查案例、会引法条、还能给出行动建议的“劳动法小助理”。</p><p>现在，每当有人再来问我劳动法相关的问题，我就直接把知识库的链接甩过去！几秒钟之内，他们就能收到一份清晰、准确、靠谱的答案。</p><p>过去，那些让我分身乏术的日常咨询，现在我不但不再烦恼，有的时候反而还有一点小期待！那种感觉，怎么跟你形容呢，就像家里有个特别争气的孩子，总忍不住想让他在叔叔阿姨们面前“露一手”、“秀一下”。</p><p>既然都说到这里了，那就让孩子出来给大家展示一下吧！</p><p>怎么样，咱家这孩子还算优秀吧？大家也可以自己去 Get 笔记上用用试试。 我并不是技术高手，也不会写代码。这件事能做成，关键是因为我知道，哪些资料可靠、哪些法律已经更新、哪些案例更具有参考价值。 所以，<strong>真正让AI落地的，从来不是工具，而是你的行业经验</strong>。 最后，我想用三句话来总结我今天的分享：</p><ol><li>知识库，是解决垂直专业领域知识问答的利器！</li><li>搭建优质知识库，必须要“喂”给它“好东西”——而找好东西，需要依靠你的行业经验。</li><li>想要随时随地收集“好东西”，找到一个趁手的好工具就足够了。</li></ol><p>以上就是我的分享，希望能对你有所启发。谢谢大家！</p>',41)])])}const d=e(o,[["render",i]]);export{m as __pageData,d as default};
